import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Why Tracium?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/why-tracium.md","filePath":"guide/why-tracium.md"}'),i={name:"guide/why-tracium.md"};function s(n,e,l,u,h,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="why-tracium" tabindex="-1">Why Tracium? <a class="header-anchor" href="#why-tracium" aria-label="Permalink to &quot;Why Tracium?&quot;">​</a></h1><h2 id="the-paradigm-shift" tabindex="-1">The Paradigm Shift <a class="header-anchor" href="#the-paradigm-shift" aria-label="Permalink to &quot;The Paradigm Shift&quot;">​</a></h2><p><strong>Before Tracium:</strong> Code executes → state disappears → we infer from logs.</p><p><strong>After Tracium:</strong> Code executes → state becomes structured, replayable, queryable data.</p><p>This is the same shift that happened with:</p><ul><li><strong>Kafka</strong> — before: events disappear. After: events are stored, replayed, streamed.</li><li><strong>Docker</strong> — before: environments are inconsistent. After: execution environments are standardized.</li><li><strong>Git</strong> — before: code changes are lost. After: every change is tracked, diffable, reversible.</li></ul><p>Tracium does this for <strong>execution itself</strong>.</p><h2 id="what-existing-tools-miss" tabindex="-1">What Existing Tools Miss <a class="header-anchor" href="#what-existing-tools-miss" aria-label="Permalink to &quot;What Existing Tools Miss&quot;">​</a></h2><h3 id="debuggers" tabindex="-1">Debuggers <a class="header-anchor" href="#debuggers" aria-label="Permalink to &quot;Debuggers&quot;">​</a></h3><p>Show you the current state at a breakpoint. But:</p><ul><li>Ephemeral — gone when you close the session</li><li>Local only — can&#39;t share or replay</li><li>Manual — you have to know where to look</li></ul><h3 id="observability-prometheus-grafana-jaeger" tabindex="-1">Observability (Prometheus, Grafana, Jaeger) <a class="header-anchor" href="#observability-prometheus-grafana-jaeger" aria-label="Permalink to &quot;Observability (Prometheus, Grafana, Jaeger)&quot;">​</a></h3><p>Show you metrics and spans. But:</p><ul><li>No state — you see &quot;request failed&quot; not &quot;user.balance = -100&quot;</li><li>Shallow — spans tell you which service, not what happened inside</li><li>Aggregated — individual execution paths are lost</li></ul><h3 id="code-visualizers-pythontutor-etc" tabindex="-1">Code Visualizers (PythonTutor, etc.) <a class="header-anchor" href="#code-visualizers-pythontutor-etc" aria-label="Permalink to &quot;Code Visualizers (PythonTutor, etc.)&quot;">​</a></h3><p>Show animated execution. But:</p><ul><li>Toy only — break down on real code</li><li>Not infrastructure — can&#39;t be consumed by other tools</li><li>Ephemeral — no persistence, no querying</li></ul><h3 id="logs" tabindex="-1">Logs <a class="header-anchor" href="#logs" aria-label="Permalink to &quot;Logs&quot;">​</a></h3><p>The universal fallback. But:</p><ul><li>Partial — only what someone thought to log</li><li>Unstructured — grep-able text, not queryable data</li><li>Lossy — most state is never logged</li></ul><h2 id="what-tracium-enables" tabindex="-1">What Tracium Enables <a class="header-anchor" href="#what-tracium-enables" aria-label="Permalink to &quot;What Tracium Enables&quot;">​</a></h2><h3 id="_1-replay-any-execution" tabindex="-1">1. Replay Any Execution <a class="header-anchor" href="#_1-replay-any-execution" aria-label="Permalink to &quot;1. Replay Any Execution&quot;">​</a></h3><p>Record execution once, replay it forever. Debug a production issue from last week by loading its trace.</p><h3 id="_2-compare-executions" tabindex="-1">2. Compare Executions <a class="header-anchor" href="#_2-compare-executions" aria-label="Permalink to &quot;2. Compare Executions&quot;">​</a></h3><p>Diff two traces to see exactly what changed. &quot;My refactor should not change behavior — did it?&quot;</p><h3 id="_3-state-level-observability" tabindex="-1">3. State-Level Observability <a class="header-anchor" href="#_3-state-level-observability" aria-label="Permalink to &quot;3. State-Level Observability&quot;">​</a></h3><p>Go beyond metrics. See the actual variable values, heap state, and execution path at any point.</p><h3 id="_4-ai-over-execution" tabindex="-1">4. AI Over Execution <a class="header-anchor" href="#_4-ai-over-execution" aria-label="Permalink to &quot;4. AI Over Execution&quot;">​</a></h3><p>Give an LLM real execution data instead of static code. &quot;Why did this request fail?&quot; answered with actual state.</p><h3 id="_5-execution-as-infrastructure" tabindex="-1">5. Execution as Infrastructure <a class="header-anchor" href="#_5-execution-as-infrastructure" aria-label="Permalink to &quot;5. Execution as Infrastructure&quot;">​</a></h3><p>Build tools on top of execution data. Monitoring dashboards, regression detection, onboarding tools — all consuming the same UEF traces.</p>',31)])])}const b=a(i,[["render",s]]);export{p as __pageData,b as default};
